import {
    Box,
    Button,
    ButtonGroup,
    Flex,
    Grid,
    IconButton,
    Select,
    Text,
    useBreakpointValue,
  } from "@chakra-ui/react";
  import React, { useEffect, useState } from "react";
  import { Link, useNavigate } from "react-router-dom";
  import { Table, Thead, Tbody, Tr, Th, Td } from "@chakra-ui/react";
  import { AddIcon, EditIcon } from "@chakra-ui/icons";
  import { useDispatch, useSelector } from "react-redux";
  import convertDateFormat, {
    deleteProduct,
    getProduct,
  } from "../../Redux/AdminReducer/action";
  import Pagination from "./Pagination";
  import AdminNavTop from "../AdminNavTop";
  import Navbar from "../UserComponents/UserNavbar";

const Add = () => {

    const store = useSelector((store) => store.AdminReducer.data);
    const dispatch = useDispatch();
    const [page, setPage] = useState(1);
    const [search, setSearch] = useState("");
    const [order, setOrder] = useState("");
    const limit = 4;
    const tableSize = useBreakpointValue({ base: "sm", sm: "md", md: "lg" });
    const courseSize = useBreakpointValue({ base: "md", sm: "lg", md: "xl" });
  
    const handleSearch = (e) => {
      setSearch(e.target.value);
      // console.log(search)
    };
    const handleSelect = (e) => {
      const { value } = e.target;
      setOrder(value);
    };
    // console.log(order)
  
    useEffect(() => {
      dispatch(getProduct(page, limit, search, order));
    }, [page, search, order, limit]);

    const navigate = useNavigate();
  
    const handleVideos = (id, title) => {
        navigate(`/admin/videos/add/${id}`, { state: { id, title } });
      };
  
    const handlePageChange = (page) => {
      setPage(page);
    };
    // console.log("store.length",store.length)
    const count = 4;
    // console.log("count",count)
  
    const handlePageButton = (val) => {
      setPage((prev) => prev + val);
    };

  return (
  <Box bg="#f7f9fa" minH="100vh" p={6}>
    <AdminNavTop handleSearch={handleSearch} />

    <Box
      mt="80px"
      bg="white"
      p={6}
      borderRadius="lg"
      boxShadow="lg"
    >
      {/* HEADER */}
      <Flex
        justify="space-between"
        align="center"
        mb={6}
        flexWrap="wrap"
        gap={4}
      >
        <Text fontSize="xl" fontWeight="bold">
          Course Management
        </Text>

        <Flex gap={3}>
          <Select w="200px" onChange={handleSelect}>
            <option value="asc">Price ↑</option>
            <option value="desc">Price ↓</option>
          </Select>

          <Button
            bg="#A435F0"
            color="white"
            _hover={{ bg: "#8710d8" }}
            onClick={() => navigate("/admin/addCourse")}
          >
            + Create Course
          </Button>
        </Flex>
      </Flex>

      {/* TABLE */}
      <Box overflowX="auto">
        <Table variant="simple">
          <Thead bg="gray.50">
            <Tr>
              <Th>Title</Th>
              <Th>Date</Th>
              <Th>Category</Th>
              <Th>Price</Th>
              <Th>Teacher</Th>
              <Th textAlign="center">Actions</Th>
            </Tr>
          </Thead>

          <Tbody>
            {store?.map((el) => (
              <Tr
                key={el._id}
                _hover={{ bg: "gray.50", cursor: "pointer" }}
              >
                <Td fontWeight="medium">{el.title}</Td>
                <Td>{convertDateFormat(el.createdAt)}</Td>
                <Td>{el.category}</Td>
                <Td color="#A435F0" fontWeight="bold">
                  ${el.price}
                </Td>
                <Td>{el.teacher}</Td>

                <Td>
                  <Flex justify="center" gap={2}>
                    <Button
                      size="sm"
                      variant="outline"
                      _hover={{ bg: "#f3e8ff" }}
                      onClick={() => handleVideos(el._id, el.title)}
                    >
                      Videos
                    </Button>

                    <IconButton
                      icon={<EditIcon />}
                      size="sm"
                      variant="ghost"
                    />
                  </Flex>
                </Td>
              </Tr>
            ))}
          </Tbody>
        </Table>
      </Box>

      {/* PAGINATION */}
      <Flex justify="flex-end" mt={6} gap={2}>
        <Button
          disabled={page <= 1}
          onClick={() => handlePageButton(-1)}
        >
          Prev
        </Button>

        <Pagination
          totalCount={count}
          current_page={page}
          handlePageChange={handlePageChange}
        />

        <Button
          disabled={page >= count}
          onClick={() => handlePageButton(1)}
        >
          Next
        </Button>
      </Flex>
    </Box>
  </Box>
);
}

export default Add
